video.megatech.global.bat_script:
@echo off
setlocal enabledelayedexpansion
chcp 65001 >nul
title Chuyen PNG sang MP4 - Xu ly da phuong phap

echo ===================================================
echo BAT DAU XU LY CHUYEN DOI FILE PNG SANG MP4
echo ===================================================
echo.

REM Tao thu muc log
if not exist logs mkdir logs
set /a total=0
set /a success=0
set /a failed=0

REM Dem tong so file png/ts/m4s trung gian
for %%i in (*.png) do set /a total+=1
if !total! equ 0 (
    for %%i in (*.ts) do set /a total+=1
)
if !total! equ 0 (
    for %%i in (*.m4s) do set /a total+=1
)
echo Tong so file segments: %total%
echo.

REM Tao file list cho cac phuong phap
if exist tslist.txt del tslist.txt
if exist mylist.txt del mylist.txt

set /a count=0
REM Xu ly tung file
for %%i in (*.png *.ts *.m4s) do (
    set /a count+=1
    set filename=%%~ni
    echo [%count%/%total%] Dang xu ly: %%i

    REM Thu cac phuong phap theo thu tu
    call :ProcessFile "%%i" "%%~ni"

    if !errorlevel! equ 0 (
        set /a success+=1
        echo   -> THANH CONG: %%~ni.ts
        echo file '%%~ni.ts' >> tslist.txt
    ) else (
        set /a failed+=1
        echo   -> THAT BAI: %%~ni.ts
        echo %%i >> failed_files.txt
    )
    echo.
)

echo ===================================================
echo KET QUA XU LY:
echo   Tong so: %total%
echo   Thanh cong: %success%
echo   That bai: %failed%
echo ===================================================

if %success% gtr 0 (
    echo.
    echo Dang tien hanh ghep cac file TS thanh MP4...

    REM Thu cac phuong phap ghep
    call :ConcatFiles

    if exist final_output.mp4 (
        echo.
        echo HOAN THANH! File ket qua: final_output.mp4
    ) else (
        echo.
        echo LOI: Khong the ghep file!
    )
) else (
    echo.
    echo KHONG CO FILE NAO XU LY THANH CONG!
)

echo.
exit /b

:ProcessFile
set input=%~1
set output=%~2
set output_ts=%output%.ts
set logfile=logs\%output%.log

echo     Thu phuong phap 1: Copy truc tiep voi BSF > %logfile%
ffmpeg -f mpegts -i %input% -c copy -bsf:v h264_mp4toannexb -y %output_ts% >> %logfile% 2>&1
if %errorlevel% equ 0 (
    if exist %output_ts% (
        exit /b 0
    )
)

echo     Thu phuong phap 2: Encode video (libx264) >> %logfile%
ffmpeg -f mpegts -i %input% -c:v libx264 -preset ultrafast -crf 23 -c:a copy -bsf:a aac_adtstoasc -y %output_ts% >> %logfile% 2>&1
if %errorlevel% equ 0 (
    if exist %output_ts% (
        exit /b 0
    )
)

echo     Thu phuong phap 3: Encode ca video va audio >> %logfile%
ffmpeg -f mpegts -i %input% -c:v libx264 -preset ultrafast -crf 23 -c:a aac -b:a 128k -y %output_ts% >> %logfile% 2>&1
if %errorlevel% equ 0 (
    if exist %output_ts% (
        exit /b 0
    )
)

echo     Thu phuong phap 4: Bo qua loi (ignore_err) >> %logfile%
ffmpeg -f mpegts -err_detect ignore_err -i %input% -c:v libx264 -preset ultrafast -c:a copy -y %output_ts% >> %logfile% 2>&1
if %errorlevel% equ 0 (
    if exist %output_ts% (
        exit /b 0
    )
)

echo     Thu phuong phap 5: Extract H264 va dong goi lai >> %logfile%
ffmpeg -f mpegts -i %input% -c:v copy -bsf:v h264_mp4toannexb -f h264 -y temp.h264 >> %logfile% 2>&1
if %errorlevel% equ 0 (
    ffmpeg -f h264 -i temp.h264 -i %input% -map 0:v -map 1:a? -c:v copy -c:a copy -y %output_ts% >> %logfile% 2>&1
    if %errorlevel% equ 0 (
        if exist %output_ts% (
            del temp.h264 2>nul
            exit /b 0
        )
    )
)
del temp.h264 2>nul

echo     Thu phuong phap 6: Chuyen sang MP4 truoc >> %logfile%
ffmpeg -f mpegts -i %input% -c:v libx264 -preset ultrafast -c:a aac -movflags +faststart -y temp.mp4 >> %logfile% 2>&1
if %errorlevel% equ 0 (
    ffmpeg -i temp.mp4 -c copy -f mpegts -y %output_ts% >> %logfile% 2>&1
    if %errorlevel% equ 0 (
        if exist %output_ts% (
            del temp.mp4 2>nul
            exit /b 0
        )
    )
)
del temp.mp4 2>nul

exit /b 1

:ConcatFiles
echo     Thu phuong phap ghep 1: Copy truc tiep
ffmpeg -f concat -safe 0 -i tslist.txt -c copy -y final_output.mp4 2> concat.log
if %errorlevel% equ 0 (
    if exist final_output.mp4 (
        echo     -> THANH CONG
        exit /b 0
    )
)

echo     Thu phuong phap ghep 2: Them genpts
ffmpeg -f concat -safe 0 -i tslist.txt -c copy -fflags +genpts -y final_output.mp4 2>> concat.log
if %errorlevel% equ 0 (
    if exist final_output.mp4 (
        echo     -> THANH CONG
        exit /b 0
    )
)

echo     Thu phuong phap ghep 3: Them BSF audio
ffmpeg -f concat -safe 0 -i tslist.txt -c copy -bsf:a aac_adtstoasc -fflags +genpts -y final_output.mp4 2>> concat.log
if %errorlevel% equ 0 (
    if exist final_output.mp4 (
        echo     -> THANH CONG
        exit /b 0
    )
)

echo     Thu phuong phap ghep 4: Ghep thanh TS truoc
ffmpeg -f concat -safe 0 -i tslist.txt -c copy -f mpegts -y temp_all.ts 2>> concat.log
if %errorlevel% equ 0 (
    ffmpeg -i temp_all.ts -c copy -bsf:a aac_adtstoasc -y final_output.mp4 2>> concat.log
    if %errorlevel% equ 0 (
        if exist final_output.mp4 (
            del temp_all.ts 2>nul
            echo     -> THANH CONG
            exit /b 0
        )
    )
)
del temp_all.ts 2>nul

exit /b 1
